function GlowOrb({ cx, cy, rx, ry, color, opacity }: { cx: number; cy: number; rx: number; ry: number; color: string; opacity: number }) {
  return <ellipse cx={cx} cy={cy} rx={rx} ry={ry} fill={color} opacity={opacity} style={{ filter: "blur(60px)" }} />;
}

